#include <stdio.h>

typedef long long (*operation_fn)(long long, long long);
static long long add(long long a, long long b) { return a + b; }
static long long multiply(long long a, long long b) { return a * b; }

int main(void) {
    char operation;
    long long a, b;
    if (scanf(" %c %lld %lld", &operation, &a, &b) != 3) return 1;
    operation_fn function = operation == '+' ? add : operation == '*' ? multiply : NULL;
    if (function == NULL) { puts("invalid"); return 0; }
    printf("%lld\n", function(a, b));
    return 0;
}
